import{_ as a,o as e,c as r,ae as o}from"./chunks/framework.B6gjLfeO.js";const b=JSON.parse('{"title":"Tapjoy","description":"","frontmatter":{"title":"Tapjoy","slug":"tapjoy"},"headers":[],"relativePath":"marketer-hub/tapjoy.md","filePath":"marketer-hub/tapjoy.md"}'),n={name:"marketer-hub/tapjoy.md"};function i(d,t,s,l,h,p){return e(),r("div",null,[...t[0]||(t[0]=[o('<p><em>[Image: 1328]</em>.png &quot;Tapjoy + branch.png&quot;)</p><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p><a href="http://tapjoy.com" target="_blank" rel="noreferrer">Tapjoy</a> is a leading mobile advertising and app monetization company. Our platform empowers advertisers to connect with over one billion monthly active users through value exchange advertising that drives awareness, engagement, and the metrics that matter most to their overall growth. We’re also revolutionizing the market research industry with MobileVoice®, a market research solution that gives mobile users a voice of their own. Companies such as Scopely, Glu, Ludia, and many of the Top 200 grossing app publishers trust our platform to monetize their content, grow their audiences, and reward their users. Founded in 2007 and headquartered in San Francisco, Tapjoy is a global organization with offices in Santa Barbara, Boston, London, Beijing, Tokyo, and Seoul. For more information, visit <a href="http://www.tapjoy.com" target="_blank" rel="noreferrer">www.tapjoy.com</a>.</p><h3 id="partner-capabilities" tabindex="-1">Partner Capabilities <a class="header-anchor" href="#partner-capabilities" aria-label="Permalink to &quot;Partner Capabilities&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Capability</th><th>Details</th></tr></thead><tbody><tr><td>Company Type</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Deep Linking</td><td>Supported</td></tr><tr><td>Attribution</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Ad Campaign Types</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Ad Formats</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Click Types</td><td>- Server-side click</td></tr><tr><td>Supported Platforms</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Link Wrapping</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Cost Ingestion Support</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Cost Ingestion Types</td><td>Contact support at Tapjoy for more information.</td></tr><tr><td>Pricing Models</td><td>- CPI - CPC - CPA - CPV - CPE</td></tr></tbody></table><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><p>In order to enable Tapjoy, you need to have completed the following:</p><ol><li><p>Created a <a href="https://dashboard.branch.io/" target="_blank" rel="noreferrer">Branch Dashboard</a>.</p></li><li><p>Have Branch&#39;s Performance <a href="./packaging.html">product</a> enabled for your Branch Account.</p></li><li><p>Implemented the Branch SDK into your mobile app (<a href="./ios-sdk-overview.html">iOS</a> | <a href="./android-sdk-overview.html">Android</a>)</p><ul><li><a href="./track-branch-events.html">Track events</a></li></ul></li><li><p>Running campaigns through Tapjoy.</p></li></ol><h2 id="enable-tapjoy" tabindex="-1">Enable Tapjoy <a class="header-anchor" href="#enable-tapjoy" aria-label="Permalink to &quot;Enable Tapjoy&quot;">​</a></h2><h3 id="_1-enable-tapjoy-in-branch" tabindex="-1">1. Enable Tapjoy in Branch <a class="header-anchor" href="#_1-enable-tapjoy-in-branch" aria-label="Permalink to &quot;1. Enable Tapjoy in Branch&quot;">​</a></h3><p>In the Branch Dashboard under <strong>Ads</strong> &gt; <a href="https://dashboard.branch.io/ads/partner-management" target="_blank" rel="noreferrer"><strong>Partner Management</strong></a>, find/search for Tapjoy. If you&#39;re already logged into the Branch Dashboard, you can also click <a href="https://dashboard.branch.io/ads/partner-management/a_tapjoy?tab=settings" target="_blank" rel="noreferrer">here</a> to go there directly.</p><p>Click the <strong>Save &amp; Enable</strong> button.</p><p>.png &quot;Tapjoy enable.png&quot;)</p><h3 id="_2-configure-postbacks" tabindex="-1">2. Configure Postbacks <a class="header-anchor" href="#_2-configure-postbacks" aria-label="Permalink to &quot;2. Configure Postbacks&quot;">​</a></h3><p>Enabling Tapjoy will automatically enable the following postbacks:</p><ul><li>INSTALL</li><li>OPEN</li><li>PURCHASE</li></ul><p>.png &quot;Tapjoy postbacks.png&quot;)</p><p>You can configure these postbacks or add more under the <a href="https://dashboard.branch.io/ads/partner-management/a_tapjoy?tab=postback" target="_blank" rel="noreferrer"><strong>Postback Config</strong></a> tab.</p><h4 id="send-all-events" tabindex="-1">Send All Events <a class="header-anchor" href="#send-all-events" aria-label="Permalink to &quot;Send All Events&quot;">​</a></h4><p>Optionally, you can check the checkbox for a given postback for sending all events. When checked, all events will be sent regardless of attribution. Otherwise, the postback will only fire for events attributed to Tapjoy.</p><h4 id="adding-postbacks" tabindex="-1">Adding Postbacks <a class="header-anchor" href="#adding-postbacks" aria-label="Permalink to &quot;Adding Postbacks&quot;">​</a></h4><p>Click the <strong>Add New Postback</strong> button at the bottom of the screen. A modal will appear that will allow you to select an event that you are tracking with the Branch SDKs (including Custom Events).</p><p>.gif &quot;Add New Postbacks.gif&quot;)</p><p>For more in-depth postback configurations, view our guides:</p><ul><li><a href="./basic-postback-configuration.html">Basic Postback Configuration</a></li><li><a href="./advanced-postback-configuration.html">Advanced Postback Configuration</a></li><li><strong>Recommended</strong> 👍 <a href="./testing-postbacks.html">Test Postbacks</a></li></ul><h3 id="_3-configure-attribution-windows" tabindex="-1">3. Configure Attribution Windows <a class="header-anchor" href="#_3-configure-attribution-windows" aria-label="Permalink to &quot;3. Configure Attribution Windows&quot;">​</a></h3><p>After configuring your events, navigate to the <a href="https://dashboard.branch.io/ads/partner-management/a_tapjoy?tab=attribution_windows" target="_blank" rel="noreferrer"><strong>Attribution Windows</strong></a> tab to set windows by attribution type.</p><h4 id="recommended-attribution-windows" tabindex="-1">Recommended Attribution Windows <a class="header-anchor" href="#recommended-attribution-windows" aria-label="Permalink to &quot;Recommended Attribution Windows&quot;">​</a></h4><table tabindex="0"><thead><tr><th>Attribution Type</th><th>Window</th></tr></thead><tbody><tr><td>click to session start</td><td>90 days</td></tr><tr><td>click to install</td><td>30 days</td></tr><tr><td>click to conversion event</td><td>90 days</td></tr><tr><td>impression to session start</td><td>1 day</td></tr><tr><td>impression to install</td><td>1 day</td></tr><tr><td>impression to conversion event.</td><td>1 day</td></tr></tbody></table><h3 id="_4-create-branch-ad-link" tabindex="-1">4. Create Branch Ad Link <a class="header-anchor" href="#_4-create-branch-ad-link" aria-label="Permalink to &quot;4. Create Branch Ad Link&quot;">​</a></h3><p>Next, you&#39;ll need to create a Branch Ad Link for your Tapjoy campaigns in order for Branch to properly attribute conversions.</p><p>[.png)</p><p>help.branch.io</p><p>Create Ad Links](/docs/ad-links)</p><p>The Branch Ad Link you create will be placed in your Tapjoy campaign.</p><h3 id="_5-verify-data-in-branch" tabindex="-1">5. Verify Data in Branch <a class="header-anchor" href="#_5-verify-data-in-branch" aria-label="Permalink to &quot;5. Verify Data in Branch&quot;">​</a></h3><p>After launching your Tapjoy campaigns, and conversions begin to happen, you&#39;ll want to verify data is being sent from Branch to Tapjoooy. You can look at the <a href="https://dashboard.branch.io/liveview/webhooks" target="_blank" rel="noreferrer">Branch Dashboard&#39;s Liveview Webhook Records</a> and apply the following filter:</p><table tabindex="0"><thead><tr><th>Filter</th><th>Operator</th><th>Value</th></tr></thead><tbody><tr><td>ad partner (3p)</td><td>equals</td><td><code>a_tapjoy</code></td></tr></tbody></table><p>Once applied, data should flow through the Liveview, and you can see the data being sent to Tapjoy from Branch.</p>',39)])])}const u=a(n,[["render",i]]);export{b as __pageData,u as default};
